"""Re-derive dev-cohort (Perez 2022) pseudobulk restricted to the frozen
30,165-gene sealed-cohort intersection, raw-count-level restriction then
CPM+log1p over the restricted total -- per PREREG Section 8's literal text
and the human decision locking this convention on 2026-07-21, BEFORE any
sealed data was scored.

This is a distinct, additional artifact from the original committed
results/l2_dev_pseudobulk_counts.parquet (261 x 61,497, full dev gene
space, used for the official dev-cohort internal CV AUROC=0.9839 already
committed and unchanged). This restricted version exists only to make a
valid, gene-space-matched final model fit for scoring the sealed cohort.

Real code, real math: sum raw counts per donor per gene (same proven
batched-query + vectorized-scatter-add pattern as
kaggle_kernels/l2_pseudobulk/l2_pseudobulk.py, including its
remove_unused_categories() Categorical-artifact fix), restricted to the
30,165 intersection genes, CPM-normalized over that restricted total, log1p.
"""

import base64
import gzip
import json
import subprocess
import sys
import time
import traceback

DATASET_ID = "218acb0f-9f2f-4f76-b90b-15a4b7c7f629"
CENSUS_VERSION = "2025-11-08"

# gzip+base64 of results/gene_space_intersection.txt (30,165 Ensembl IDs,
# one per line), embedded so this kernel has no dependency on uploading a
# separate file. Decoded and verified against the expected count below.
INTERSECTION_GENES_B64 = ""


def log(msg):
    print(f"[l2-dev-pseudobulk-restricted] {msg}", flush=True)


def run(cmd):
    log(f"$ {cmd}")
    subprocess.run(cmd, shell=True, check=True)


log("installing cellxgene_census")
run(f"{sys.executable} -m pip install -q cellxgene_census")

import cellxgene_census  # noqa: E402
import tiledbsoma as soma  # noqa: E402
import numpy as np  # noqa: E402
import pandas as pd  # noqa: E402

SUMMARY = {}

try:
    t_start = time.time()

    intersection_genes = gzip.decompress(base64.b64decode(INTERSECTION_GENES_B64)).decode("ascii").splitlines()
    intersection_genes = [g for g in intersection_genes if g]
    log(f"embedded intersection gene list: {len(intersection_genes)} genes")
    assert len(intersection_genes) == 30165, f"expected 30165, got {len(intersection_genes)}"
    intersection_set = set(intersection_genes)

    census = cellxgene_census.open_soma(census_version=CENSUS_VERSION)
    exp = census["census_data"]["homo_sapiens"]
    value_filter = f"dataset_id == '{DATASET_ID}'"

    with exp.axis_query(
        measurement_name="RNA",
        obs_query=soma.AxisQuery(value_filter=value_filter),
    ) as query:
        n_genes_full = query.n_vars
        n_obs_total = query.n_obs
        log(f"query scope: {n_obs_total} cells x {n_genes_full} genes (full dev gene space)")

        var_table = query.var(column_names=["soma_joinid", "feature_id"]).concat().to_pandas()
        # Restrict the var-side lookup to ONLY the intersection genes:
        # unmatched genes map to -1 and are dropped during accumulation.
        kept_var = var_table[var_table["feature_id"].isin(intersection_set)]
        log(f"dev genes matching the intersection: {len(kept_var)} (expected 30165)")
        assert len(kept_var) == 30165, f"expected 30165 matching genes, got {len(kept_var)}"

        # dense column order = kept_var's feature_id order (arbitrary but
        # fixed/deterministic; recorded via the output parquet's column
        # names, not assumed to match any other ordering)
        kept_feature_ids = kept_var["feature_id"].tolist()
        col_of_feature_id = {fid: i for i, fid in enumerate(kept_feature_ids)}
        max_joinid = int(var_table["soma_joinid"].max())
        var_col_of_joinid = np.full(max_joinid + 1, -1, dtype=np.int64)
        for _, row in kept_var.iterrows():
            var_col_of_joinid[int(row["soma_joinid"])] = col_of_feature_id[row["feature_id"]]

        obs_table = query.obs(column_names=["soma_joinid", "donor_id"]).concat().to_pandas()
        obs_table["donor_id"] = obs_table["donor_id"].cat.remove_unused_categories()
        assert len(obs_table["donor_id"].cat.categories) == obs_table["donor_id"].nunique(), (
            "donor_id still has unused categories after remove_unused_categories()"
        )
        donor_ids_sorted = sorted(obs_table["donor_id"].unique().tolist())
        assert len(donor_ids_sorted) == 261, f"expected 261 donors, got {len(donor_ids_sorted)}"
        donor_row_of_id = {d: i for i, d in enumerate(donor_ids_sorted)}
        obs_joinids = obs_table["soma_joinid"].to_numpy()
        donor_row_of_joinid = np.full(int(obs_joinids.max()) + 1, -1, dtype=np.int64)
        donor_row_of_joinid[obs_joinids] = obs_table["donor_id"].map(donor_row_of_id).to_numpy()

        gene_sums = np.zeros((261, 30165), dtype=np.float64)
        n_chunks = 0
        t_stream_start = time.time()
        for x_tbl in query.X("raw").tables():
            soma_dim_0 = x_tbl["soma_dim_0"].to_numpy()
            soma_dim_1 = x_tbl["soma_dim_1"].to_numpy()
            values = x_tbl["soma_data"].to_numpy()
            donor_rows = donor_row_of_joinid[soma_dim_0]
            gene_cols = var_col_of_joinid[soma_dim_1]
            valid = gene_cols >= 0  # drop entries for genes outside the intersection
            np.add.at(gene_sums, (donor_rows[valid], gene_cols[valid]), values[valid])
            n_chunks += 1
            if n_chunks % 20 == 0:
                log(f"chunk {n_chunks}, {time.time()-t_stream_start:.1f}s elapsed")

        t_stream_end = time.time()

    census.close()

    stream_seconds = t_stream_end - t_stream_start
    log(f"streaming+aggregation: {stream_seconds:.1f}s for {n_obs_total} cells "
        f"({n_obs_total/stream_seconds:.2f} cells/sec)")

    # CPM over the RESTRICTED (30,165-gene) total, per the locked convention
    totals = gene_sums.sum(axis=1, keepdims=True)
    zero_total = [donor_ids_sorted[i] for i in np.where(totals.ravel() <= 0)[0]]
    if zero_total:
        raise RuntimeError(f"donors with zero restricted-total counts: {zero_total}")
    cpm = gene_sums / totals * 1_000_000.0
    log1p_cpm = np.log1p(cpm)

    df = pd.DataFrame(log1p_cpm, index=donor_ids_sorted, columns=kept_feature_ids)
    df.index.name = "donor_id"
    out_path = "/kaggle/working/l2_dev_pseudobulk_counts_restricted.parquet"
    df.to_parquet(out_path, compression="zstd")
    log(f"wrote {out_path}: shape={df.shape}")

    SUMMARY.update({
        "status": "success",
        "n_donors": 261,
        "n_genes_restricted": 30165,
        "n_cells_total": int(n_obs_total),
        "stream_seconds": stream_seconds,
        "cells_per_sec": n_obs_total / stream_seconds,
        "total_seconds": time.time() - t_start,
        "output_shape": list(df.shape),
    })

except Exception:
    log("FAILED:")
    traceback.print_exc()
    SUMMARY["status"] = "failed"
    SUMMARY["error"] = traceback.format_exc()

with open("/kaggle/working/l2_dev_pseudobulk_restricted_run_summary.json", "w") as f:
    json.dump(SUMMARY, f, indent=2, default=str)

log("=== FINAL SUMMARY ===")
print(json.dumps(SUMMARY, indent=2, default=str), flush=True)
